// Helper to get unique folders
export const SWI_FOLDERS = [...new Set(SWI_CATALOG.map(s => s.folder))];

// Helper to get SWIs by folder
export function getSWIsByFolder(folder: string): SWIDocument[] {
  return SWI_CATALOG.filter(s => s.folder === folder);
}
